def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject (most common subject across all triples)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    main_subject = max(subject_counts, key=subject_counts.get)

    # Group triples by subject
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Build sentence with main subject as focus
    main_parts = []
    other_parts = []

    for t in subject_triples.get(main_subject, []):
        pred = t.predicate
        obj = t.object

        if pred == "birthPlace":
            main_parts.append(f"born in {obj}")
        elif pred == "birthDate":
            main_parts.append(f"born on {obj}")
        elif pred == "birthYear":
            main_parts.append(f"born in {obj}")
        elif pred == "deathPlace":
            main_parts.append(f"died in {obj}")
        elif pred == "deathDate":
            main_parts.append(f"died on {obj}")
        elif pred == "deathYear":
            main_parts.append(f"died in {obj}")
        elif pred == "nationality":
            main_parts.append(f"{obj} national")
        elif pred == "party":
            main_parts.append(f"member of the {obj} party")
        elif pred == "office":
            main_parts.append(f"held the office of {obj}")
        elif pred == "successor":
            main_parts.append(f"succeeded by {obj}")
        elif pred == "predecessor":
            main_parts.append(f"preceded by {obj}")
        elif pred == "spouse":
            main_parts.append(f"married to {obj}")
        elif pred == "residence":
            main_parts.append(f"resides at {obj}")
        elif pred == "region":
            main_parts.append(f"from the region of {obj}")
        elif pred == "country":
            main_parts.append(f"from {obj}")
        elif pred == "capital":
            other_parts.append(f"whose capital is {obj}")
        elif pred == "largestCity":
            other_parts.append(f"with largest city {obj}")
        elif pred == "currency":
            other_parts.append(f"using {obj} currency")
        elif pred == "language":
            other_parts.append(f"where {obj} is spoken")
        elif pred == "officialLanguage":
            other_parts.append(f"with official language {obj}")
        elif pred == "leader":
            other_parts.append(f"led by {obj}")
        elif pred == "battle":
            main_parts.append(f"participated in the {obj}")
        elif pred == "almaMater":
            main_parts.append(f"studied at {obj}")
        elif pred == "profession":
            main_parts.append(f"worked as a {obj}")
        elif pred == "religion":
            main_parts.append(f"follows {obj}")
        elif pred == "militaryBranch":
            main_parts.append(f"served in the {obj}")
        elif pred == "militaryRank":
            main_parts.append(f"held the rank of {obj}")
        elif pred == "state":
            main_parts.append(f"from {obj}")
        elif pred == "award":
            main_parts.append(f"received the {obj}")
        elif pred == "activeYearsStartDate":
            main_parts.append(f"started in {obj}")
        elif pred == "activeYearsEndDate":
            main_parts.append(f"ended in {obj}")
        else:
            main_parts.append(f"{pred} {obj}")

    # Build final sentence
    sentence_parts = []
    if main_parts:
        sentence_parts.append(f"{main_subject} is " + ", ".join(main_parts[:-1]) + " and " + main_parts[-1] if len(main_parts) > 1 else f"{main_subject} is {main_parts[0]}")

    if other_parts:
        sentence_parts.append(f"{main_subject} is " + ", ".join(other_parts[:-1]) + " and " + other_parts[-1] if len(other_parts) > 1 else f"{main_subject} is {other_parts[0]}")

    return ". ".join(sentence_parts) + "." if sentence_parts else ""

